import { useNavigate } from "react-router-dom";
import logo from "../assets/logo.png";

export default function Navbar() {
  const nav = useNavigate();

  return (
    <div className="bg-gray-100 shadow-md">

      {/* Top Header */}
      <div className="flex justify-between items-center px-6 py-4">

        {/* LEFT SIDE */}
        <div className="flex items-center gap-3">

          {/* LOGO */}
          <img
            src={logo}
            alt="logo"
            className="h-9 w-9 object-contain transition-all duration-300 ease-in-out hover:scale-110 hover:drop-shadow-[0_0_6px_rgba(0,0,0,0.3)]"
          />

          {/* TITLE */}
          <h1 className="text-2xl font-bold">
            AARV Train Booking System
          </h1>

        </div>

        {/* RIGHT SIDE */}
        <div className="space-x-2">
          <button
            onClick={() => nav("/")}
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 transition"
          >
            Login
          </button>

          <button
            onClick={() => nav("/signup")}
            className="bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600 transition"
          >
            Signup
          </button>
        </div>

      </div>

      {/* MENU */}
      <div className="flex justify-center gap-10 p-3 border-t">
        <button
          onClick={() => nav("/home")}
          className="bg-gray-300 px-6 py-2 rounded hover:bg-gray-400 transition"
        >
          Home
        </button>

        <button
          onClick={() => nav("/my")}
          className="bg-gray-300 px-6 py-2 rounded hover:bg-gray-400 transition"
        >
          Bookings
        </button>

        <button className="bg-gray-300 px-6 py-2 rounded hover:bg-gray-400 transition">
          Account
        </button>
      </div>

    </div>
  );
}
